const body = $input.first().json.body || $input.first().json;
const rfq_id = body.rfq_id;
const deadline = body.deadline || null;
// selected_vendor_ids: absent/null => send to ALL (back-compat). present array => honour exactly.
const selected_vendor_ids = Array.isArray(body.selected_vendor_ids) ? body.selected_vendor_ids : null;
if (!rfq_id) {
  return [{ json: { error: true, message: 'Missing required field: rfq_id' } }];
}
return [{ json: { error: false, rfq_id, deadline, selected_vendor_ids } }];

// Read vendor row from the LOOP item (current $json is the Drive permission, not the vendor).
const v = $('Loop Vendors').item.json;
const rfq = $('Fetch RFQ').first().json;
const name = v.contact_person || 'Procurement Manager';
const sender = rfq.created_by || 'Procurement Officer';
const deadline = rfq.deadline || '[To be confirmed]';
let body = rfq.covering_email_body || '';
body = body.split('[Contact Person]').join(name);
body = body.split('[SENDER_NAME]').join(sender);
body = body.split('[To be confirmed]').join(deadline);
return { json: { email_to: v.email_to, contact_person: name, body, subject: rfq.covering_email_subject } };

// Emit vendor rows exactly once so Loop Vendors iterates vendors (not the RFQ item).
// Filter to selected_vendor_ids when the frontend supplies them (checkbox selection).
const sel = $('Validate Input').first().json.selected_vendor_ids;
const allow = Array.isArray(sel) ? new Set(sel) : null; // null => no filter (send to all)
const seen = new Set(); const out = [];
for (const v of $('Fetch Vendors').all()) {
  const id = v.json.id;
  if (seen.has(id)) continue;
  if (allow && !allow.has(v.json.vendor_id)) continue; // skip unchecked vendors
  seen.add(id); out.push({ json: v.json });
}
return out;

// Build the webhook response payload here so Respond node only reads $json
// (avoids getParentNodes failure when Respond sits after the loop).
const rfqId = $('Validate Input').first().json.rfq_id;
let folder = null;
try { folder = $('Create Drive Folder').first().json.id; } catch(e) {}
return [{ json: { success: true, rfq_id: rfqId,
  drive_folder_url: folder ? ('https://drive.google.com/drive/folders/' + folder) : null } }];

